export const getGetNearbySeedListingsUrl = (params: GetNearbySeedListingsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/v1/seed/listings/nearby?${stringifiedParams}` : `/api/v1/seed/listings/nearby`
}

